package main

import (
	"fmt"
	"strings"

	"github.com/gdamore/tcell/v2"
)

// ==========================================
// ESTREUTURA DA LISTA DUPLAMENTE ENCADEADA
// ==========================================

type Node[T any] struct {
	Value T
	next  *Node[T]
	prev  *Node[T]
	root  *Node[T]
}

func (n *Node[T]) Next() *Node[T] {
	return n.next
}

func (n *Node[T]) Prev() *Node[T] {
	return n.prev
}

type List[T any] struct {
	root *Node[T]
	size int
}

func NewList[T any]() *List[T] {
	root := &Node[T]{}
	root.next = root
	root.prev = root
	root.root = root
	return &List[T]{root: root, size: 0}
}

func (l *List[T]) PushBack(value T) {
	l.Insert(l.root, value)
}

func (l *List[T]) Insert(it *Node[T], value T) *Node[T] {
	n := &Node[T]{Value: value, root: l.root}
	n.prev = it.prev
	n.next = it
	it.prev.next = n
	it.prev = n
	l.size++
	return n
}

func (l *List[T]) Size() int {
	return l.size
}

func (l *List[T]) Clear() {
	l.root.next = l.root
	l.root.prev = l.root
	l.size = 0
}

func (l *List[T]) End() *Node[T] {
	return l.root
}

func (l *List[T]) Front() *Node[T] {
	if l.size == 0 {
		return l.root
	}
	return l.root.next
}

func (l *List[T]) Back() *Node[T] {
	if l.size == 0 {
		return l.root
	}
	return l.root.prev
}

func (l *List[T]) Erase(n *Node[T]) *Node[T] {
	if n == l.root {
		return l.root
	}
	n.prev.next = n.next
	n.next.prev = n.prev
	l.size--
	return n.next
}

func (l *List[T]) IndexOf(n *Node[T]) int {
	if n == l.root {
		return l.size
	}
	if n.root != l.root {
		return -1
	}
	i := 0
	for it := l.root.next; it != n; it = it.next {
		i++
		if i >= l.size {
			return -1
		}
	}
	return i
}

func (l *List[T]) String() string {
	values := []string{}
	for n := l.root.next; n != l.root; n = n.next {
		values = append(values, fmt.Sprint(n.Value))
	}
	return "[" + strings.Join(values, ", ") + "]"
}

// ==========================================
// ESTRUTURA E LÓGICA DO EDITOR DE TEXTO
// ==========================================

type Editor struct {
	texto   *List[*List[rune]]
	it_line *Node[*List[rune]]
	it_char *Node[rune]
	screen  tcell.Screen
	style   tcell.Style
}

func (e *Editor) InsertChar(r rune) {
	e.it_char = e.it_line.Value.Insert(e.it_char, r)
	e.it_char = e.it_char.Next()
}

func (e *Editor) KeyLeft() {
	if e.it_char.Prev() != e.it_line.Value.End() {
		e.it_char = e.it_char.Prev() 
	} else if e.it_line.Prev() != e.texto.End() { // Corrigido: Evita crash no topo do arquivo
		e.it_line = e.it_line.Prev()
		e.it_char = e.it_line.Value.Back()
	}
}

func (e *Editor) KeyRight() {
	if e.it_char.Next() != e.it_line.Value.End() {
		e.it_char = e.it_char.Next()
	} else if e.it_line.Next() != e.texto.End() { // Corrigido: Evita crash no fim do arquivo
		e.it_line = e.it_line.Next()
		e.it_char = e.it_line.Value.Front()
	}
}

func (e *Editor) KeyEnter() {
	nova := NewList[rune]()
	e.texto.Insert(e.it_line.Next(), nova)

	curr := e.it_char
	for curr != e.it_line.Value.End() {
		next := curr.Next()
		nova.PushBack(curr.Value)
		e.it_line.Value.Erase(curr)
		curr = next
	}

	e.it_line = e.it_line.Next()
	e.it_char = e.it_line.Value.Front()
}

func (e *Editor) KeyUp() {
	if e.it_line.Prev() == e.texto.End() { // Corrigido: Evita crash ao tentar subir na primeira linha
		return
	}

	coluna_index := e.it_line.Value.IndexOf(e.it_char)

	e.it_line = e.it_line.Prev()
	e.it_char = e.it_line.Value.Front()

	for i := 0; i < coluna_index; i++ {
		if e.it_char == e.it_line.Value.End() {
			break
		}
		e.it_char = e.it_char.Next()
	}
}

func (e *Editor) KeyDown() {
	if e.it_line.Next() == e.texto.End() { // Corrigido: Evita crash ao tentar descer na última linha
		return
	}

	coluna_index := e.it_line.Value.IndexOf(e.it_char)

	e.it_line = e.it_line.Next()
	e.it_char = e.it_line.Value.Front()

	for i := 0; i < coluna_index; i++ {
		if e.it_char == e.it_line.Value.End() {
			break
		}
		e.it_char = e.it_char.Next()
	}
}

func (e *Editor) KeyBackspace() {
	alvo := e.it_char.Prev()
	if alvo == e.it_line.Value.End() {
		return
	}
	e.it_line.Value.Erase(alvo)
}

func (e *Editor) KeyDelete() {
	alvo := e.it_char.Next()
	if alvo == e.it_line.Value.End() {
		return
	}
	e.it_line.Value.Erase(alvo)
}

func NewEditor() *Editor {
	e := &Editor{}

	screen, err := tcell.NewScreen()
	if err != nil {
		panic(fmt.Sprintf("erro ao criar a tela: %v", err)) // Corrigido: Interrompe se falhar
	}
	if err := screen.Init(); err != nil {
		panic(fmt.Sprintf("erro ao iniciar a tela: %v", err)) // Corrigido: Interrompe se falhar
	}

	e.screen = screen
	e.texto = NewList[*List[rune]]()
	e.texto.PushBack(NewList[rune]())
	e.it_line = e.texto.Front()
	e.it_char = e.it_line.Value.Back()

	e.style = tcell.StyleDefault.Foreground(tcell.ColorWhite).Background(tcell.ColorBlack)
	e.screen.SetStyle(e.style)
	e.screen.Clear()
	return e
}

func (e *Editor) Draw() {
	e.screen.Clear()
	x := 0
	y := 0
	for line := e.texto.Front(); line != e.texto.End(); line = line.Next() {
		for char := line.Value.Front(); ; char = char.Next() {
			data := char.Value
			if char == line.Value.End() {
				data = '⤶'
			}
			if data == ' ' {
				data = '·'
			}
			if char == e.it_char {
				e.screen.SetContent(x, y, data, nil, e.style.Reverse(true))
			} else {
				e.screen.SetContent(x, y, data, nil, e.style)
			}
			x++
			if char == line.Value.End() {
				break
			}
		}
		y++
		x = 0
	}
	e.screen.Show()
}

func (e *Editor) MainLoop() {
	for {
		ev := e.screen.PollEvent()
		switch ev := ev.(type) {
		case *tcell.EventKey:
			switch ev.Key() {
			case tcell.KeyEsc, tcell.KeyCtrlC:
				return
			case tcell.KeyEnter:
				e.KeyEnter()
			case tcell.KeyLeft:
				e.KeyLeft()
			case tcell.KeyRight:
				e.KeyRight()
			case tcell.KeyUp:
				e.KeyUp()
			case tcell.KeyDown:
				e.KeyDown()
			case tcell.KeyBackspace, tcell.KeyBackspace2:
				e.KeyBackspace()
			case tcell.KeyDelete:
				e.KeyDelete()
			default:
				if ev.Rune() != 0 {
					e.InsertChar(ev.Rune())
				}
			}
			e.Draw()
		case *tcell.EventResize:
			e.screen.Sync()
			e.Draw()
		}
	}
}

// ==========================================
// PONTO DE ENTRADA DO PROGRAMA
// ==========================================

func main() {
	editor := NewEditor()
	defer editor.screen.Fini() // Garante que o terminal volte ao normal se o app fechar
	editor.Draw()
	editor.MainLoop()
}
